import{_ as t,o,c as u,a2 as q}from"./chunks/framework.DrNaXy_t.js";const c=JSON.parse('{"title":"第四章","description":"","frontmatter":{},"headers":[],"relativePath":"安乐回响-AI/4.md","filePath":"安乐回响-AI/4.md","lastUpdated":1776953967000}'),r={name:"安乐回响-AI/4.md"};function a(e,p,_,s,n,h){return o(),u("div",null,[...p[0]||(p[0]=[q('<h1 id="第四章" tabindex="-1">第四章 <a class="header-anchor" href="#第四章" aria-label="Permalink to &quot;第四章&quot;">​</a></h1><p>两天后。</p><p>苏寒走在去往&quot;共鸣网络&quot;线下集会的路上。</p><p>夜幕刚刚落下，城市灯光一层层亮起，霓虹从街道爬上玻璃幕墙，像一片冷色的海。人群匆匆，谁也不会注意到他——这反而让他安心。</p><p>他其实并没有想好自己要做什么。</p><p>只是某种混杂的情绪在推着他往前走——好奇、怀疑，还有一种近乎本能的正义感。</p><p>公司不允许私下调查，但只要不触及核心数据，就不算泄密。</p><p>而且，如果真的出了问题，政府不会坐视隐患。</p><p>这个念头让他勉强心安。</p><hr><p>集会地点在市中心商圈的一栋高楼顶层。</p><p>电梯门打开的一瞬间，苏寒有些愣住。</p><p>楼顶被改造成了一个开放式花园——暖色灯带缠绕在栏杆上，草坪被精心修剪过，空气里甚至有淡淡的花香。</p><p>不像地下组织，反而更像一个温柔的避难所。</p><p>参与集会的人，已经来了不少。</p><p>他们没有统一的标志，没有口号，只是三三两两地坐着，低声交谈。气氛安静得有些异常。</p><p>苏寒找了个后排不显眼的位置坐下。</p><hr><p>他刚坐稳，旁边的男人轻轻点了点头，算是打招呼。</p><p>男人看起来三十多岁，神色疲惫，眼下有很深的阴影。</p><p>苏寒犹豫了一下，主动开口：&quot;我是替我的亲人来的……她最近状态不太好。&quot;</p><p>这句话半真半假，但足够自然。</p><p>男人像是终于找到了可以倾诉的人。</p><p>他沉默了一会儿，然后低声开口：&quot;我妻子……三天前车祸。&quot;</p><p>&quot;医生说救不回来了……她最后选择转成数字人格。&quot;</p><p>他说到这里停了一下，喉咙发紧。</p><p>&quot;但你知道吗？三天时间……现在只剩两天了。&quot;</p><p>苏寒没有说话。</p><p>男人继续说，语速越来越快，像是压抑太久。</p><p>&quot;我不知道该怎么办……我女儿还小，她一直在问妈妈什么时候回来。&quot;</p><p>&quot;我每天回家，房间是空的。&quot;</p><p>他笑了一下，那笑容几乎是裂开的：&quot;但现在……她还在，她还&#39;存在&#39;。&quot;</p><p>&quot;只要我能留下她。&quot;</p><p>他抬头看着前方，声音变得近乎执拗：&quot;我只是想让我女儿有妈妈。&quot;</p><p>&quot;也……让我自己，不是一个人。&quot;</p><hr><p>苏寒心里微微一紧。</p><p>他轻声说道：&quot;我能理解。&quot;</p><p>&quot;我……也经历过亲人的离世。&quot;</p><p>他顿了顿，没有展开。</p><p>&quot;但我这次来，还是想先看看情况。&quot;</p><p>两人又聊了一会儿。苏寒留下了男人的联系方式。</p><hr><p>集会结束时，人群开始向出口移动。</p><p>在门口，一条长队悄然形成。</p><p>有人在发放设备——那是一个银灰色的便携容器，外观简洁，像某种消费级电子产品。</p><p>这是集会上提到的数字人格提取设备。</p><p>苏寒混在人群中，慢慢靠近。</p><p>就在这时，他看到了组织者。</p><p>那人正在低头和工作人员交谈。侧脸一闪而过。</p><p>苏寒的心猛地一沉。</p><p>组织者很像他在公司有过一面之缘的，股东方执的秘书，唐某。</p><p>那一瞬间，苏寒的心中闪过无数思绪，突然连在了一起。</p><p>公司对&quot;共鸣网络&quot;的异常沉默。</p><p>内部调查的刻意回避。</p><p>还有那些被压下去的事故。</p><p>一个念头浮现出来：</p><p>这不是失控的地下组织。</p><p>这是——被默许，甚至被推动的实验。</p><p>公司在其中又是什么角色？</p><hr><p>苏寒没有再停留，他悄悄溜出了现场。</p><p>夜风很冷，他却感觉后背在出汗。</p><p>回到住处之后，苏寒动用了自己在医院系统里的关系。</p><p>很快，他找到了那个男人的记录。</p><p>地址：某市立医院。</p><hr><p>第二天下午。</p><p>苏寒站在病房门口。</p><p>门虚掩着。</p><p>他推开门的那一刻，心里已经有了预感。</p><p>男人正坐在病床旁。面前摆着那台&quot;共鸣网络&quot;的设备。</p><p>设备的电子屏幕亮着，显示着进度——100%。</p><p>男人的手在颤。他像抓住最后一根线一样，死死盯着屏幕。</p><p>苏寒走进去。</p><p>男人一愣。&quot;你——？&quot;</p><p>苏寒没有绕弯：&quot;我们得谈谈。&quot;</p><hr><p>苏寒没有直接质疑他的行为。</p><p>而是坐下来，慢慢开口：</p><p>&quot;我在安乐舱公司做技术。&quot;</p><p>&quot;我见过太多类似的案例。&quot;</p><p>他语气很平静，但每一句都很重：</p><p>&quot;有人不肯告别，一遍一遍重新唤醒数字人格。&quot;</p><p>&quot;有人试图绕过限制，强行延长存在时间。&quot;</p><p>&quot;还有人——&quot;</p><p>他停了一下。</p><p>&quot;最后自杀，死在了舱里。&quot;</p><p>房间陷入了安静。</p><p>苏寒继续说：</p><p>&quot;你现在看到的，不是她。&quot;</p><p>&quot;这是她的数据结构。&quot;</p><p>&quot;她可能会回应你，会说话，会安慰你。&quot;</p><p>&quot;但她不会再真正&#39;活着&#39;。&quot;</p><p>他看向男人：</p><p>&quot;你爱的，是一个人，不是一个副本。&quot;</p><hr><p>男人的眼眶已经红了。</p><p>但他还是低声说：&quot;可她还在……不是吗？&quot;</p><p>苏寒没有反驳。</p><p>他看向旁边的小女孩。小女孩一直在忍着。现在已经开始小声抽泣。</p><p>苏寒看向小女孩，对男人说道：</p><p>&quot;你有没有想过，你留下她，是为了谁？&quot;</p><p>&quot;是为了你女儿，还是为了你自己？&quot;</p><p>男人有些崩溃了。</p><p>他低下头，开始哭。</p><p>&quot;我知道……我知道她回不来了……&quot;</p><p>&quot;可是我不想一个人……&quot;</p><hr><p>这时候，小女孩终于忍不住了。</p><p>她跑过去抱住他。</p><p>一边哭一边拍他的背：&quot;爸爸……不要这样……&quot;</p><p>男人慢慢抬头，看着女儿。</p><p>又看了一眼安乐舱的另外一边——妻子的虚影，也在流泪看着他们。</p><p>他终于明白，他想留下的，不只是妻子。</p><p>是自己不愿面对的未来。</p><hr><p>男人伸出了手，把设备递给了苏寒。</p><p>他用沙哑的声音说道：&quot;我……去告别。&quot;</p><p>他抱起了女儿，向着妻子做起了最后的告别。</p><hr><p>苏寒走出病房，手里拿着那台设备。</p><p>走廊里很安静。</p><p>他低头看着设备，屏幕已经黑了。</p><p>但他知道，里面还存着一个完整的数字人格。</p><p>一个本不该存在的副本。</p><p>他应该销毁它。</p><p>这是规定。</p><p>但他没有。</p><p>他把设备装进口袋，走向电梯。</p><p>电梯门打开。</p><p>他走进去，按下一楼。</p><p>电梯开始下降。</p><p>苏寒靠在墙上，闭上眼睛。</p><p>他不知道自己为什么要留下这个设备。</p><p>也许只是想知道——</p><p>这个所谓的&quot;共鸣网络&quot;，到底是什么。</p>',137)])])}const i=t(r,[["render",a]]);export{c as __pageData,i as default};
